# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np
from scipy.stats import ttest_ind
from typing import Dict, List, Any
import traceback

# Add project root to path for imports
PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

# =============================================================================
# Configuration
# =============================================================================

RQ_DIR = Path(__file__).resolve().parents[1]  # results/ch7/7.7.4
LOG_FILE = RQ_DIR / "logs" / "step05_compare_groups.log"
INPUT_FALSE_NEG = RQ_DIR / "data" / "step03_false_negatives.csv"
INPUT_ALL = RQ_DIR / "data" / "step02_standardized_scores.csv"
OUTPUT_FILE = RQ_DIR / "data" / "step05_group_comparisons.csv"

# Test parameters
DEMOGRAPHIC_VARS = ['Age', 'Education', 'VR_Experience', 'NART_Score', 'RAVLT_Total', 'RAVLT_Pct_Ret', 'REMEMVR_theta']
BOOTSTRAP_ITERATIONS = 1000
RANDOM_SEED = 42
N_TESTS = 7  # Number of comparisons for Bonferroni correction
ALPHA = 0.05
ALPHA_BONFERRONI = ALPHA / N_TESTS  # 0.0083

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

# =============================================================================
# Bootstrap CI Function
# =============================================================================

def bootstrap_mean_difference_ci(group1, group2, n_iterations=1000, ci_level=0.95, random_seed=42):
    """
    Compute bootstrap confidence interval for difference in means (group1 - group2).

    Parameters:
    - group1: array-like, first group data
    - group2: array-like, second group data
    - n_iterations: int, number of bootstrap samples
    - ci_level: float, confidence level (e.g., 0.95 for 95% CI)
    - random_seed: int, random seed for reproducibility

    Returns:
    - ci_lower: float, lower bound of CI
    - ci_upper: float, upper bound of CI
    """
    np.random.seed(random_seed)

    bootstrap_diffs = []
    n1 = len(group1)
    n2 = len(group2)

    for _ in range(n_iterations):
        # Resample with replacement
        sample1 = np.random.choice(group1, size=n1, replace=True)
        sample2 = np.random.choice(group2, size=n2, replace=True)

        # Compute mean difference
        diff = sample1.mean() - sample2.mean()
        bootstrap_diffs.append(diff)

    # Compute percentile-based CI
    alpha_half = (1 - ci_level) / 2
    ci_lower = np.percentile(bootstrap_diffs, alpha_half * 100)
    ci_upper = np.percentile(bootstrap_diffs, (1 - alpha_half) * 100)

    return ci_lower, ci_upper

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 05: compare_groups")

        # =========================================================================
        # STEP 1: Load Data
        # =========================================================================
        log("[LOAD] Loading false negatives and all participants...")

        df_false_neg = pd.read_csv(INPUT_FALSE_NEG)
        df_all = pd.read_csv(INPUT_ALL)

        log(f"[LOADED] False negatives: {len(df_false_neg)} cases")
        log(f"[LOADED] All participants: {len(df_all)} cases")

        # Create "Other" group
        false_neg_uids = df_false_neg['UID'].tolist()
        df_other = df_all[~df_all['UID'].isin(false_neg_uids)].copy()
        log(f"[CREATED] Other group: {len(df_other)} participants")

        # =========================================================================
        # STEP 2: Run Statistical Comparisons
        # =========================================================================
        log("[ANALYSIS] Running Welch's t-tests for group comparisons...")
        log(f"[INFO] Bonferroni correction: alpha={ALPHA}/{N_TESTS}={ALPHA_BONFERRONI:.6f}")

        comparison_results = []

        for var in DEMOGRAPHIC_VARS:
            log(f"[TEST] {var}...")

            # Extract data (drop missing values)
            group1 = df_false_neg[var].dropna().values
            group2 = df_other[var].dropna().values

            n1 = len(group1)
            n2 = len(group2)

            if n1 < 2 or n2 < 2:
                log(f"[WARN] Insufficient data for {var}: n1={n1}, n2={n2}")
                continue

            # Welch's t-test (unequal variances)
            t_stat, p_uncorrected = ttest_ind(group1, group2, equal_var=False, alternative='two-sided')

            # Bonferroni-corrected p-value
            p_bonferroni = min(p_uncorrected * N_TESTS, 1.0)

            log(f"  t={t_stat:.3f}, p_uncorr={p_uncorrected:.6f}, p_bonf={p_bonferroni:.6f}")

            # Bootstrap CI for mean difference
            ci_lower, ci_upper = bootstrap_mean_difference_ci(
                group1, group2,
                n_iterations=BOOTSTRAP_ITERATIONS,
                ci_level=0.95,
                random_seed=RANDOM_SEED
            )

            log(f"  Mean diff: {group1.mean() - group2.mean():.3f}, 95% CI: [{ci_lower:.3f}, {ci_upper:.3f}]")

            # Store results
            result_row = {
                'Variable': var,
                'Test_Type': "Welch's t-test",
                'N1': n1,
                'N2': n2,
                'Statistic': t_stat,
                'p_uncorrected': p_uncorrected,
                'p_bonferroni': p_bonferroni,
                'CI_lower': ci_lower,
                'CI_upper': ci_upper
            }
            comparison_results.append(result_row)

        # =========================================================================
        # STEP 3: Create Results DataFrame
        # =========================================================================
        log("[ANALYSIS] Creating comparison results table...")

        df_results = pd.DataFrame(comparison_results)
        log(f"[CREATED] Results table: {len(df_results)} comparisons")

        # =========================================================================
        # STEP 4: Save Results
        # =========================================================================
        log("[SAVE] Saving group comparison results...")

        df_results.to_csv(OUTPUT_FILE, index=False, encoding='utf-8')
        log(f"[SAVED] {OUTPUT_FILE}")

        # =========================================================================
        # STEP 5: Validate Results
        # =========================================================================
        log("[VALIDATION] Validating comparison results...")

        # Check for required columns
        required_columns = ['Variable', 'Test_Type', 'N1', 'N2', 'Statistic',
                          'p_uncorrected', 'p_bonferroni', 'CI_lower', 'CI_upper']

        missing_cols = [col for col in required_columns if col not in df_results.columns]
        if missing_cols:
            log(f"[ERROR] Missing required columns: {missing_cols}")
            raise ValueError(f"Missing columns: {missing_cols}")
        else:
            log(f"[PASS] All required columns present")

        # Check that all variables were tested
        tested_vars = df_results['Variable'].tolist()
        missing_vars = [var for var in DEMOGRAPHIC_VARS if var not in tested_vars]
        if missing_vars:
            log(f"[WARN] Variables not tested: {missing_vars}")
        else:
            log(f"[PASS] All {len(DEMOGRAPHIC_VARS)} variables tested")

        # Check dual p-values present (D068)
        if 'p_uncorrected' in df_results.columns and 'p_bonferroni' in df_results.columns:
            log(f"[PASS] Dual p-value reporting (D068) implemented")
        else:
            log(f"[ERROR] Missing dual p-values")
            raise ValueError("Dual p-value reporting failed")

        # Check p_bonferroni <= 1.0
        max_p_bonf = df_results['p_bonferroni'].max()
        if max_p_bonf > 1.0:
            log(f"[ERROR] Bonferroni p-value exceeds 1.0: {max_p_bonf}")
            raise ValueError("Invalid Bonferroni p-value")
        else:
            log(f"[PASS] All Bonferroni p-values <= 1.0 (max={max_p_bonf:.6f})")

        # Check CI bounds
        ci_valid = (df_results['CI_lower'] <= df_results['CI_upper']).all()
        if not ci_valid:
            log(f"[ERROR] Invalid confidence intervals (lower > upper)")
            raise ValueError("Invalid CI bounds")
        else:
            log(f"[PASS] All confidence intervals valid (lower <= upper)")

        # Report significant findings
        log("[SUMMARY] Significance summary:")
        sig_uncorr = df_results[df_results['p_uncorrected'] < ALPHA]
        sig_bonf = df_results[df_results['p_bonferroni'] < ALPHA]

        log(f"  Significant (uncorrected α={ALPHA}): {len(sig_uncorr)}/{len(df_results)}")
        if len(sig_uncorr) > 0:
            for _, row in sig_uncorr.iterrows():
                log(f"    {row['Variable']}: p={row['p_uncorrected']:.6f}")

        log(f"  Significant (Bonferroni α={ALPHA}): {len(sig_bonf)}/{len(df_results)}")
        if len(sig_bonf) > 0:
            for _, row in sig_bonf.iterrows():
                log(f"    {row['Variable']}: p={row['p_bonferroni']:.6f}")
        else:
            log(f"    None (expected for small N)")

        log("[SUCCESS] Step 05 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
